"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger, SheetDescription } from "@/components/ui/sheet";
import { Edit } from "lucide-react";
import { updateCompany } from "@/app/actions";

interface EditCompanySheetProps {
    company: {
        id: string;
        name: string;
        cnpj: string | null;
        address: string | null;
    };
}

export function EditCompanySheet({ company }: EditCompanySheetProps) {
    const [open, setOpen] = useState(false);

    async function handleSubmit(formData: FormData) {
        await updateCompany(formData);
        setOpen(false);
    }

    return (
        <Sheet open={open} onOpenChange={setOpen}>
            <SheetTrigger asChild>
                <Button variant="ghost" size="sm">
                    <Edit className="w-4 h-4 text-slate-400 hover:text-slate-600" />
                </Button>
            </SheetTrigger>
            <SheetContent className="px-8">
                <SheetHeader>
                    <SheetTitle>Editar Empresa</SheetTitle>
                    <SheetDescription>Atualize os dados desta entidade jurídica.</SheetDescription>
                </SheetHeader>
                <form action={handleSubmit} className="space-y-4 mt-6">
                    <input type="hidden" name="id" value={company.id} />
                    <div className="space-y-2">
                        <Label htmlFor="name">Nome / Razão Social</Label>
                        <Input id="name" name="name" defaultValue={company.name} required />
                    </div>
                    <div className="space-y-2">
                        <Label htmlFor="cnpj">CNPJ</Label>
                        <Input id="cnpj" name="cnpj" defaultValue={company.cnpj || ""} />
                    </div>
                    <div className="space-y-2">
                        <Label htmlFor="address">Endereço Sede</Label>
                        <Input id="address" name="address" defaultValue={company.address || ""} />
                    </div>
                    <Button type="submit" className="w-full">Salvar Alterações</Button>
                </form>
            </SheetContent>
        </Sheet>
    );
}
